mapper.select:
SELECT 
    sc.*,
    s.supplier_name,
    u.real_name as operator_name
FROM supplier_cooperation sc
LEFT JOIN supplier s ON sc.supplier_id = s.supplier_id
LEFT JOIN sys_user u ON sc.operator_id = u.user_id


        AND sc.supplier_id = #{supplierId}


        AND sc.record_type = #{recordType}


        AND sc.create_time >= #{startDate}


        AND sc.create_time <= #{endDate}


ORDER BY sc.create_time DESC
